        self._emb_matrix: Optional[np.ndarray] = None
        self._metadata: Optional[list[dict]] = None
        self._loaded = False
        self._load_error: Optional[str] = None

    def _ensure_loaded(self) -> bool:
        if self._loaded:
            return self._emb_matrix is not None
        self._loaded = True
