                    self._metadata.append(json.loads(line))
            return True
        except Exception as e:
            self._load_error = str(e)
            return False

    def _retrieve(self, query: str) -> list[dict]:
        if not self._ensure_loaded():
            return []
        q_emb = embed_text(query)
        if q_emb is None:
            return []
